import { InjectionToken } from '@angular/core';
import { ValidatorFn } from '@angular/forms';
import { Observable } from 'rxjs';

export type TypeIconVariant = 'Colour' | 'Duotone' | 'Fill' | 'Line';
export type TypeIconSize = 10 | 16 | 20 | 24 | 32 | 48;

export type TypeLabelVariant =
  | 'h1'
  | 'h1Bold'
  | 'h2'
  | 'h2Bold'
  | 'h3'
  | 'h3Bold'
  | 'p1'
  | 'p1Bold'
  | 'p2'
  | 'p2Bold'
  | 'p3'
  | 'p3Bold'
  | 'p4'
  | 'p4Bold'
  | 'interactionLarge'
  | 'interactionLargeBold'
  | 'interactionMedium'
  | 'interactionMediumBold'
  | 'interactionSmall'
  | 'interactionSmallBold'
  | 'avatarLabel';

export type TypeStatusLabel =
  | 'Standard'
  | 'Success'
  | 'Hot'
  | 'Warning'
  | 'Disabled'
  | 'RHBPremierBanking';

export interface FNInputAffix {
  icon?: string;
  text?: string;
  onClick?: (e: Event) => void;
}

export interface FNInputVisibilityCondition {
  dependsOn: string;
  showWhen: any;
  hideWhen?: any;
}

export interface FNInputCommonProps<T = any> {
  fieldType: 'FNInput';
  name: string;
  label: string;
  placeholder?: string;
  className?: string;
  required?: boolean;
  value?: T;
  disabled?: boolean;
  hidden?: boolean;
  readOnly?: boolean;
  floatLabelVariant?: 'in' | 'over' | 'on';
  validators?: ValidatorFn[];
  errors?: { [key: string]: string };
  rows?: number;
  prefix?: FNInputAffix;
  suffix?: FNInputAffix;
  hasSuccessBorder?: boolean;
  visibilityCondition?: FNInputVisibilityCondition;
  helperText?: string;
  isAlphanumeric?: boolean;
  hideOptional?: boolean;
  isAddressLine?: boolean;
  color?: string;
  labelVariant?: TypeLabelVariant;
  statusLabel?: TypeStatusLabel;
  labelSize?: string;
  valueColor?: string;
  valueSize?: string;
  isCopyText?: boolean;
  hasGenerateKey?: boolean;
  onGenerateKey?: () => void;
}

export interface FNTextInputProps<T = any> extends FNInputCommonProps<T> {
  type: 'text' | 'email' | 'textarea' | 'hidden';
  cols?: number;
  maxLength?: number;
  icon?: {
    name: string;
    variant: TypeIconVariant;
    size: TypeIconSize;
  };
}

export interface FNPasswordProps extends FNInputCommonProps<string> {
  type: 'password';
  toggleMask?: boolean;
  feedback?: boolean;
  weakLabel?: string;
  mediumLabel?: string;
  strongLabel?: string;
}

export interface FNInputNumberProps extends FNInputCommonProps<number> {
  type: 'number';
  min?: number;
  max?: number;
  step?: number;
  minFractionDigits?: number;
  maxFractionDigits?: number;
  currency?: string;
  currencyDisplay?: 'symbol' | 'code' | 'name';
  locale?: string;
  useGrouping?: boolean;
  mode?: 'decimal' | 'currency';
  showButtons?: boolean;
  buttonLayout?: 'stacked' | 'horizontal' | 'vertical';
  incrementButtonIcon?: string;
  decrementButtonIcon?: string;
  isCurrency?: boolean;
  maxIntegerDigits?: number;
}

export type FNInputBase = FNTextInputProps | FNPasswordProps | FNInputNumberProps;

export interface FNInputHelper {
  showFormFieldMessage: (control: any, helperText: string) => boolean;
  translate: (key: string) => string;
}

import { Toast, ToastService } from 'fn-toast';

export interface FNInputToast extends ToastService {}

export const FN_TOAST_SERVICE = new InjectionToken<FNInputToast>('FN_TOAST_SERVICE');

export const DEFAULT_CURRENCY_META = [
  { code: 'USD', locale: 'en-US', symbol: '$', digit: '1.2-2' },
  { code: 'MYR', locale: 'en-MY', symbol: 'RM', digit: '1.2-2' },
  { code: 'EUR', locale: 'en-US', symbol: '€', digit: '1.2-2' },
  { code: 'GBP', locale: 'en-US', symbol: '£', digit: '1.2-2' },
  { code: 'JPY', locale: 'ja-JP', symbol: '¥', digit: '1.0-0' },
  { code: 'CNY', locale: 'zh-CN', symbol: '¥', digit: '1.2-2' },
  { code: 'INR', locale: 'en-IN', symbol: '₹', digit: '1.2-2' },
];
